    param(
        [Parameter(Mandatory)][object[]]$Artifacts,
        [Parameter(Mandatory)][int]$MaxAgeDays,
        [Parameter(Mandatory)][DateTime]$ReferenceDate
    )
    if ($MaxAgeDays -le 0) { return @() }
