function New-CleanupPlan {
    <#
    .SYNOPSIS
      Apply all retention policies and return a deletion plan.
    .OUTPUTS
      A [pscustomobject] with:
        Delete   — array of artifacts to delete (with a DeletionReasons field)
        Keep     — array of artifacts to retain
